sql:
SELECT track_name, album_id
FROM tracks
WHERE track_id = '56789' AND album_id = '12345';

SELECT SUM(duration_listened_ms) 
FROM user_listening_history 
WHERE user_id = '1';

SELECT t.track_name
FROM tracks t
WHERE t.track_id NOT IN (
    SELECT up.preferred_tracks
    FROM user_preferences up
);

SELECT artists.artist_name, genres.genre_name
FROM artists
JOIN genres ON artists.genre_id = genres.genre_id;

SELECT history_id
FROM user_listening_history
WHERE track_id IN (
    SELECT track_id
    FROM audio_features
    WHERE energy > 0.7 AND acousticness < 0.1
) AND track_id NOT IN (
    SELECT track_id
    FROM playlist_tracks
);

external_knowledge:
- "preferred musicians" refers to artists whose tracks are marked as favorites by the user;
- "chosen listener" is a reference to the specified user ID in the SQL query;
- "favorite tunes" are tracks that are marked as favorites in the playlist tracks table.

- 'edgy' refers to tracks with explicit content;
- 'lengthy' tracks are those lasting more than 250 seconds;
- 'popular' tracks have a popularity score above 70;
- 'certain tempo' means the tempo is between 100 and 150 BPM;
- 'marked as favorites by listeners' means the tracks are favorites in playlists.

sql:
SELECT user_id, played_at
FROM user_listening_history
WHERE track_id = '1' AND played_at > '2023-06-15 12:00:00';

SELECT COUNT(*) AS count
FROM user_listening_history
WHERE user_id = '1';

SELECT DISTINCT HEX(artists.artist_id) AS Artist_ID_Hex, artists.artist_name
FROM artists
JOIN user_preferences ON user_preferences.preferred_artists LIKE '%' || artists.artist_id || '%';

SELECT ulh.user_id, AVG(ulh.duration_listened_ms) AS average_duration_listened
FROM user_listening_history ulh
GROUP BY ulh.user_id;
